steps.script:
var dlg = tree.root.get_node_or_null("Main/FormationsDialog")
if dlg == null:
	return "NO_DIALOG"
return dlg.visible

var dlg = tree.root.get_node("Main/FormationsDialog")
var vp_h = int(tree.root.get_visible_rect().size.y)
return dlg.size.y == vp_h - 108 - 48

var dlg = tree.root.get_node("Main/FormationsDialog")
var vp_h = int(tree.root.get_visible_rect().size.y)
return vp_h - (dlg.position.y + dlg.size.y)

var dlg = tree.root.get_node("Main/FormationsDialog")
var vp_w = int(tree.root.get_visible_rect().size.x)
return abs((dlg.position.x + dlg.size.x / 2) - vp_w / 2) <= 1

var dlg = tree.root.get_node_or_null("Main/FormationsDialog")
if dlg == null:
	return "NO_P2_DIALOG"
if not dlg.visible:
	return "P2_DIALOG_HIDDEN"
return dlg.title

var dlg = tree.root.get_node("Main/FormationsDialog")
var vp_h = int(tree.root.get_visible_rect().size.y)
return dlg.position.y == 108 and dlg.size.y == vp_h - 108 - 48
